import{c as e,Q as a,j as r,m as n}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"Finance Customers","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/finance/customers.md","filePath":"guide/admin/finance/customers.md","lastUpdated":1778912818000}'),o={name:"guide/admin/finance/customers.md"};function i(s,t,l,d,u,h){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="finance-customers" tabindex="-1">Finance Customers <a class="header-anchor" href="#finance-customers" aria-label="Permalink to &quot;Finance Customers&quot;">​</a></h1><p>The <strong>Finance → Customers</strong> page is the entry point to per-customer billing. It is a list of every customer with their plan, status, and billing email, with a <strong>View Billing</strong> action that takes you to their full billing view.</p><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><p>Header with title and description. Toolbar with search, status filter, plan filter, <strong>Clear</strong> button, and total customer count. Table.</p><h2 id="toolbar" tabindex="-1">Toolbar <a class="header-anchor" href="#toolbar" aria-label="Permalink to &quot;Toolbar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Control</th><th>Behaviour</th></tr></thead><tbody><tr><td><strong>Search</strong></td><td>Customer name or billing email, case-insensitive substring.</td></tr><tr><td><strong>Status</strong></td><td>All / Active / Suspended / Churned.</td></tr><tr><td><strong>Plan</strong></td><td>All / Starter / Professional / Enterprise / custom plans.</td></tr><tr><td><strong>Clear</strong></td><td>Resets all filters.</td></tr></tbody></table><h2 id="columns" tabindex="-1">Columns <a class="header-anchor" href="#columns" aria-label="Permalink to &quot;Columns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Name</strong></td><td>Company name.</td></tr><tr><td><strong>Plan</strong></td><td>Display name + version. A warning icon appears if the customer is on a version older than current; tooltip shows &quot;Latest: vX&quot;.</td></tr><tr><td><strong>Status</strong></td><td>Active / Suspended / Churned badge.</td></tr><tr><td><strong>Billing Email</strong></td><td>The billing contact&#39;s email.</td></tr><tr><td><strong>Actions</strong></td><td><strong>View Billing</strong> button.</td></tr></tbody></table><h2 id="view-billing" tabindex="-1">View Billing <a class="header-anchor" href="#view-billing" aria-label="Permalink to &quot;View Billing&quot;">​</a></h2><p>The primary action on each row. Click to open the <a href="./customer-billing">Customer Billing</a> page for that customer, where you manage invoices, payments, credits, and the full billing setup.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>This page is intentionally minimal — it is just the launcher for per-customer billing work. For aggregate dashboards see <a href="./customer-finance">Customer Finance</a>.</li><li>The &quot;warning icon on plan version&quot; surfaces customers who are still on a retired version. Use that to decide who needs a plan upgrade.</li></ul>',12)])])}const g=e(o,[["render",i]]);export{m as __pageData,g as default};
